                var isCurrent = step == _currentStep;
                var isFuture = step > _currentStep;

                <div class="text-center flex-fill"
                     style="cursor: @(isCompleted ? "pointer" : "default"); opacity: @(isFuture ? "0.4" : "1");"
                     @onclick="() => GoToCompletedStep(step)">
                    <div class="rounded-circle d-inline-flex align-items-center justify-content-center mb-1"
                         style="width:36px; height:36px;
                                background: @(isCurrent ? "#0d6efd" : isCompleted ? "#198754" : "#dee2e6");
                                color: @(isFuture ? "#6c757d" : "white");
                                font-size: 0.85rem; font-weight: 600;">
                        @if (isCompleted)
                        {
                            <span>&#10003;</span>
                        }
                        else
                        {
                            @step
                        }
                    </div>
                    <div class="small @(isCurrent ? "fw-bold text-primary" : "") @(isFuture ? "text-muted" : "")">
                        @_stepNames[i]
