        @* ───── Confirmation ───── *@
        <div class="text-center py-5">
            <div class="text-success mb-3" style="font-size: 3rem;">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p class="text-muted">Your application ID is <strong>@_applicationId</strong>.</p>
            <p>Thank you for applying. We will be in touch soon.</p>
        </div>
    }
    else
    {
        @* ───── Step 1: Personal Info ───── *@
        @if (_currentStep == 1)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">Personal Information</h4>
                    <div class="mb-3">
                        <label class="form-label">Full Name <span class="text-danger">*</span></label>
                        <input class="form-control" @bind="_fullName" placeholder="Jane Doe" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" @bind="_email" placeholder="jane@example.com" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control" @bind="_phone" placeholder="(555) 123-4567" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Address <span class="text-danger">*</span></label>
                        <textarea class="form-control" rows="2" @bind="_address" placeholder="123 Main St, City, State ZIP"></textarea>
                    </div>
                    <div class="d-flex justify-content-end">
                        <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isProcessing">
                            @if (_isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Next
                        </button>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 2: Work History ───── *@
        @if (_currentStep == 2)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">Work History</h4>

                    @for (int i = 0; i < _workEntries.Count; i++)
                    {
                        var idx = i;
                        var entry = _workEntries[idx];
                        <div class="border rounded p-3 mb-3 bg-light">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Position @(idx + 1)</h6>
                                @if (_workEntries.Count > 1)
                                {
                                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                                }
                            </div>
                            <div class="row mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Company <span class="text-danger">*</span></label>
                                    <input class="form-control" @bind="entry.Company" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                    <input class="form-control" @bind="entry.Title" />
                                </div>
                            </div>
                            <div class="row mb-2">
                                <div class="col-md-4">
                                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                    <input type="date" class="form-control" @bind="entry.StartDate" />
                                </div>
                                <div class="col-md-4">
                                    <label class="form-label">End Date</label>
                                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                                </div>
                                <div class="col-md-4 d-flex align-items-end mb-1">
                                    <div class="form-check">
                                        <input class="form-check-input" type="checkbox" @bind="entry.IsCurrent" id="current-@idx" />
                                        <label class="form-check-label" for="current-@idx">Currently working here</label>
                                    </div>
                                </div>
                            </div>
                            <div class="mb-0">
                                <label class="form-label">Description</label>
                                <textarea class="form-control" rows="2" @bind="entry.Description"></textarea>
                            </div>
                        </div>
                    }

                    <button class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>

                    <div class="d-flex justify-content-between">
                        <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                        <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 3: References ───── *@
        @if (_currentStep == 3)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">References</h4>

                    @for (int i = 0; i < _references.Count; i++)
                    {
                        var idx = i;
                        var refEntry = _references[idx];
                        <div class="border rounded p-3 mb-3 bg-light">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Reference @(idx + 1)</h6>
                                @if (_references.Count > 2)
                                {
                                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                                }
                            </div>
                            <div class="row mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Name <span class="text-danger">*</span></label>
                                    <input class="form-control" @bind="refEntry.Name" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                    <input class="form-control" @bind="refEntry.Relationship" placeholder="e.g. Former Manager" />
                                </div>
                            </div>
                            <div class="row">
                                <div class="col-md-6">
                                    <label class="form-label">Email <span class="text-danger">*</span></label>
                                    <input type="email" class="form-control" @bind="refEntry.Email" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                                    <input type="tel" class="form-control" @bind="refEntry.Phone" />
                                </div>
                            </div>
                        </div>
                    }

                    @if (_references.Count < 3)
                    {
                        <button class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddReference">+ Add Reference</button>
                    }

                    <div class="d-flex justify-content-between">
                        <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                        <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 4: Cover Letter ───── *@
        @if (_currentStep == 4)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">Cover Letter</h4>
                    <div class="mb-2">
                        <textarea class="form-control" rows="10" @bind="_coverLetter" maxlength="2000"
                                  placeholder="Tell us why you're a great fit for this role..."></textarea>
                    </div>
                    <div class="text-muted small mb-3">@(_coverLetter?.Length ?? 0) / 2000 characters</div>
                    <div class="d-flex justify-content-between">
                        <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                        <button class="btn btn-primary" @onclick="NextStep">Next</button>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 5: Review & Submit ───── *@
        @if (_currentStep == 5)
        {
            <div class="card mb-3">
                <div class="card-body">
                    <div class="d-flex justify-content-between align-items-center mb-2">
                        <h5 class="mb-0">Personal Information</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@_fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                    </dl>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <div class="d-flex justify-content-between align-items-center mb-2">
                        <h5 class="mb-0">Work History</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    @foreach (var entry in _workEntries)
                    {
                        <div class="border-start border-3 border-primary ps-3 mb-3">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <span class="text-muted small">
                                @entry.StartDate.ToString("MMM yyyy") &ndash;
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                            </span>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mb-0 mt-1 small">@entry.Description</p>
                            }
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <div class="d-flex justify-content-between align-items-center mb-2">
                        <h5 class="mb-0">References</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    @foreach (var r in _references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> &mdash; @r.Relationship<br />
                            <span class="small text-muted">@r.Email &middot; @r.Phone</span>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <div class="d-flex justify-content-between align-items-center mb-2">
                        <h5 class="mb-0">Cover Letter</h5>
                        <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(4)">Edit</button>
                    </div>
                    <p class="mb-0" style="white-space: pre-wrap;">@_coverLetter</p>
                </div>
            </div>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isProcessing">
                    @if (_isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Submit Application
                </button>
            </div>
        }
    }
</div>

@code {
    private static readonly string[] _stepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep = 1;
    private bool _submitted;
    private bool _isProcessing;
    private string? _errorMessage;
    private int _applicationId;

    // Step 1 fields
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2 fields
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };

    // Step 3 fields
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 fields
    private string _coverLetter = "";

    // ── Navigation ──

    private void GoToStep(int step)
    {
        _errorMessage = null;
        _currentStep = step;
    }

    private void GoToCompletedStep(int step)
    {
        if (step < _currentStep)
            GoToStep(step);
    }

    private void PreviousStep() => GoToStep(_currentStep - 1);

    private void NextStep() => GoToStep(_currentStep + 1);

    // ── Step 1 validation ──

    private async Task NextFromPersonalInfo()
    {
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _isProcessing = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email.Trim());
            if (!valid)
            {
                _errorMessage = "Please enter a valid email address.";
                return;
            }
            NextStep();
        }
        finally
        {
            _isProcessing = false;
        }
    }

    // ── Step 2 ──

    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1)
            _workEntries.RemoveAt(index);
    }

    private void NextFromWorkHistory()
    {
        _errorMessage = null;
        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)
                || e.StartDate == default)
            {
                _errorMessage = "Please fill in company, job title, and start date for every position.";
                return;
            }
        }
        NextStep();
    }

    // ── Step 3 ──

    private void AddReference()
    {
        if (_references.Count < 3)
            _references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 2)
            _references.RemoveAt(index);
    }

    private void NextFromReferences()
    {
        _errorMessage = null;
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please fill in all fields for every reference.";
                return;
            }
        }
        NextStep();
    }

    // ── Submit ──

    private async Task SubmitApplication()
    {
        _errorMessage = null;
        _isProcessing = true;
        try
        {
            var personal = new PersonalInfo(_fullName.Trim(), _email.Trim(), _phone.Trim(), _address.Trim());
            var workHistory = new WorkHistory(_workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description ?? "")
            ).ToList());
            var refs = _references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)
            ).ToList();
            var application = new JobApplication(personal, workHistory, refs, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isProcessing = false;
        }
    }

    // ── Mutable view-models for form binding ──

    private class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

